using Payments;

namespace PaymentGateway.Tests;

[TestClass]
public sealed class ChargeAsyncTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new Payments.PaymentGateway();

    [TestMethod]
    public async Task ChargeAsync_ValidCardAndAmount_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ReturnsFalse()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ReturnsFalse()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", -10m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_EmptyOrWhitespaceToken_ThrowsArgumentException(string token)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token, 25.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_NullToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            () => _gateway.ChargeAsync(null!, 25.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFalse()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 999_999.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_SmallestValidAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_SuccessfulCharge_ReturnsUniqueChargeIds()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid_visa", 10m);
        var result2 = await _gateway.ChargeAsync("tok_valid_visa", 20m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }
}

[TestClass]
public sealed class RefundAsyncTests
{
    private Payments.PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup() => _gateway = new Payments.PaymentGateway();

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessWithRefundId()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 75.00m);
        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsTrue(refund.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(refund.RefundId));
    }

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ReturnsFalse()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_EmptyOrWhitespaceChargeId_ThrowsArgumentException(string chargeId)
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            () => _gateway.RefundAsync(chargeId));
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            () => _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_DuplicateRefund_ReturnsFalse()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);

        var firstRefund = await _gateway.RefundAsync(charge.ChargeId);
        Assert.IsTrue(firstRefund.Success);

        var secondRefund = await _gateway.RefundAsync(charge.ChargeId);
        Assert.IsFalse(secondRefund.Success, "Duplicate refund should fail");
    }

    [TestMethod]
    public async Task RefundAsync_EachRefundHasUniqueId()
    {
        var charge1 = await _gateway.ChargeAsync("tok_valid_visa", 30.00m);
        var charge2 = await _gateway.ChargeAsync("tok_valid_visa", 40.00m);

        var refund1 = await _gateway.RefundAsync(charge1.ChargeId);
        var refund2 = await _gateway.RefundAsync(charge2.ChargeId);

        Assert.AreNotEqual(refund1.RefundId, refund2.RefundId);
    }
}

